<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Bouncing Ball Physics Playground</title>
    <style>
        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
        }

        body {
            background-color: #1a1a2e;
            color: #eee;
            font-family: Arial, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            min-height: 100vh;
            padding: 20px;
        }

        h1 {
            margin-bottom: 20px;
            color: #e94560;
        }

        .container {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 15px;
        }

        canvas {
            background-color: #16213e;
            border: 2px solid #0f3460;
            box-shadow: 0 0 20px rgba(0, 0, 0, 0.5);
            cursor: crosshair;
        }

        .controls {
            display: flex;
            gap: 10px;
        }

        button {
            background-color: #e94560;
            color: white;
            border: none;
            padding: 10px 20px;
            font-size: 16px;
            cursor: pointer;
            border-radius: 5px;
            transition: background-color 0.2s, transform 0.1s;
        }

        button:hover {
            background-color: #ff6b81;
        }

        button:active {
            transform: scale(0.95);
        }

        button#play.paused {
            background-color: #4caf50;
        }
    </style>
</head>
<body>
    <h1>Bouncing Ball Physics Playground</h1>

    <div class="container">
        <canvas id="sim" width="600" height="500"></canvas>

        <div class="controls">
            <button id="drop">Drop a new ball</button>
            <button id="play">Play/Pause</button>
            <button id="clear">Clear all balls</button>
        </div>
    </div>

    <script>
        // Canvas setup
        const canvas = document.getElementById('sim');
        const ctx = canvas.getContext('2d');

        // Physics constants
        const GRAVITY = 0.5;
        const RESTITUTION = 0.75; // Energy loss on bounce (0 to 1)
        const FRICTION = 0.995;   // Air resistance

        // Simulation state
        let balls = [];
        let isRunning = true;
        let animationId = null;

        // Expose simulation API on window
        window.sim = {
            w: canvas.width,
            h: canvas.height,

            balls() {
                return balls.map(ball => ({
                    x: ball.x,
                    y: ball.y,
                    vx: ball.vx,
                    vy: ball.vy,
                    r: ball.r
                }));
            },

            addBall(x, y, vx = 0, vy = 0, r) {
                const radius = r || Math.random() * 15 + 10; // Random radius between 10 and 25
                balls.push({
                    x,
                    y,
                    vx,
                    vy,
                    r: radius,
                    color: `hsl(${Math.random() * 360}, 70%, 60%)`
                });
            },

            clear() {
                balls = [];
            },

            step(dt = 1) {
                // Apply physics to each ball
                for (let i = 0; i < balls.length; i++) {
                    const ball = balls[i];

                    // Apply gravity
                    ball.vy += GRAVITY * dt;

                    // Apply velocity with air resistance
                    ball.vx *= FRICTION;
                    ball.vy *= FRICTION;

                    // Update position
                    ball.x += ball.vx * dt;
                    ball.y += ball.vy * dt;

                    // Check for collisions with canvas boundaries

                    // Bottom edge
                    if (ball.y + ball.r > canvas.height) {
                        ball.y = canvas.height - ball.r; // Clamp to boundary
                        ball.vy *= -RESTITUTION; // Reverse velocity with energy loss
                    }

                    // Top edge
                    if (ball.y - ball.r < 0) {
                        ball.y = ball.r; // Clamp to boundary
                        ball.vy *= -RESTITUTION;
                    }

                    // Right edge
                    if (ball.x + ball.r > canvas.width) {
                        ball.x = canvas.width - ball.r; // Clamp to boundary
                        ball.vx *= -RESTITUTION;
                    }

                    // Left edge
                    if (ball.x - ball.r < 0) {
                        ball.x = ball.r; // Clamp to boundary
                        ball.vx *= -RESTITUTION;
                    }
                }

                // Redraw canvas
                draw();
            }
        };

        function draw() {
            // Clear canvas with dark background
            ctx.fillStyle = '#16213e';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            // Draw each ball
            for (const ball of balls) {
                ctx.beginPath();
                ctx.arc(ball.x, ball.y, ball.r, 0, Math.PI * 2);
                ctx.fillStyle = ball.color;
                ctx.fill();

                // Add a subtle highlight
                ctx.beginPath();
                ctx.arc(ball.x - ball.r * 0.3, ball.y - ball.r * 0.3, ball.r * 0.25, 0, Math.PI * 2);
                ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
                ctx.fill();

                // Add border
                ctx.strokeStyle = '#fff';
                ctx.lineWidth = 1;
                ctx.stroke();
            }
        }

        function animate() {
            if (isRunning) {
                window.sim.step(1);
            }
            animationId = requestAnimationFrame(animate);
        }

        // Event listeners

        // Drop button
        document.getElementById('drop').addEventListener('click', () => {
            const x = canvas.width / 2;
            const y = 50;
            window.sim.addBall(x, y, (Math.random() - 0.5) * 10, 0);
        });

        // Play/Pause button
        const playButton = document.getElementById('play');
        playButton.addEventListener('click', () => {
            isRunning = !isRunning;
            if (isRunning) {
                playButton.textContent = 'Pause';
                playButton.classList.remove('paused');
            } else {
                playButton.textContent = 'Play';
                playButton.classList.add('paused');
            }
        });

        // Clear button
        document.getElementById('clear').addEventListener('click', () => {
            window.sim.clear();
        });

        // Canvas click to add ball
        canvas.addEventListener('click', (e) => {
            const rect = canvas.getBoundingClientRect();
            const x = e.clientX - rect.left;
            const y = e.clientY - rect.top;

            // Add a new ball at the clicked position with some random velocity
            window.sim.addBall(x, y, (Math.random() - 0.5) * 15, (Math.random() - 0.5) * 15);
        });

        // Initialize with one ball
        window.sim.addBall(canvas.width / 2, canvas.height / 3);

        // Start animation loop
        animate();
    </script>
</body>
</html>
